import React from 'react';
import { BarChart, Bar, PieChart, Pie, Cell, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';

const AnalyticsDashboard = ({ analytics, loading, onRefresh }) => {
  if (loading) {
    return (
      <div className="loading">
        <div className="spinner"></div>
        <span>Loading analytics...</span>
      </div>
    );
  }

  if (!analytics) {
    return (
      <div className="card">
        <h2 className="card-title">📊 Analytics Dashboard</h2>
        <div className="alert alert-info">
          No analytics data available yet. Start by onboarding workers and processing claims.
        </div>
      </div>
    );
  }

  const { stats, riskDistribution, claimsByType, workers, fraudAlerts } = analytics;

  // Prepare chart data
  const riskData = [
    { name: 'Low Risk', value: riskDistribution.low, color: '#48bb78' },
    { name: 'Medium Risk', value: riskDistribution.medium, color: '#ed8936' },
    { name: 'High Risk', value: riskDistribution.high, color: '#f56565' }
  ];

  const claimsData = [
    { name: 'Weather Claims', value: claimsByType.weather, color: '#4299e1' },
    { name: 'Other Claims', value: claimsByType.other, color: '#9f7aea' }
  ];

  const fraudData = [
    { name: 'Safe', value: workers.filter(w => w.fraudScore <= 30).length, color: '#48bb78' },
    { name: 'Flagged', value: workers.filter(w => w.fraudScore > 30 && w.fraudScore <= 60).length, color: '#ed8936' },
    { name: 'Fraud', value: workers.filter(w => w.fraudScore > 60).length, color: '#f56565' }
  ];

  return (
    <div>
      {/* Emotional Impact Metric */}
      <div className="card">
        <h3 className="card-title">💝 Weekly Earnings Protection</h3>

        <div style={{
          background: 'linear-gradient(135deg, #f7fafc, #edf2f7)',
          borderRadius: '16px',
          padding: '2rem',
          textAlign: 'center',
          position: 'relative',
          overflow: 'hidden'
        }}>
          {/* Animated background pattern */}
          <div style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'radial-gradient(circle at 50% 50%, rgba(102, 126, 234, 0.05) 0%, transparent 70%)',
            animation: 'pulse 3s infinite'
          }} />

          <div style={{ position: 'relative', zIndex: 1 }}>
            {/* Protection Meter */}
            <div style={{
              width: '200px',
              height: '200px',
              margin: '0 auto 2rem',
              position: 'relative'
            }}>
              {/* Circular Progress Background */}
              <svg width="200" height="200" style={{ transform: 'rotate(-90deg)' }}>
                <circle
                  cx="100"
                  cy="100"
                  r="80"
                  stroke="#e2e8f0"
                  strokeWidth="12"
                  fill="none"
                />
                <circle
                  cx="100"
                  cy="100"
                  r="80"
                  stroke="url(#gradient)"
                  strokeWidth="12"
                  fill="none"
                  strokeLinecap="round"
                  strokeDasharray={`${2 * Math.PI * 80}`}
                  strokeDashoffset={`${2 * Math.PI * 80 * (1 - 0.7)}`}
                  style={{
                    transition: 'stroke-dashoffset 1s ease-in-out'
                  }}
                />
                <defs>
                  <linearGradient id="gradient" x1="0%" y1="0%" x2="100%" y2="100%">
                    <stop offset="0%" stopColor="#667eea" />
                    <stop offset="100%" stopColor="#764ba2" />
                  </linearGradient>
                </defs>
              </svg>

              {/* Center Content */}
              <div style={{
                position: 'absolute',
                top: '50%',
                left: '50%',
                transform: 'translate(-50%, -50%)',
                textAlign: 'center'
              }}>
                <div style={{
                  fontSize: '2rem',
                  fontWeight: 'bold',
                  color: '#4a5568',
                  marginBottom: '0.25rem'
                }}>
                  70%
                </div>
                <div style={{
                  fontSize: '0.9rem',
                  color: '#718096',
                  fontWeight: '500'
                }}>
                  Protected
                </div>
              </div>
            </div>

            {/* Protection Details */}
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
              gap: '1rem',
              marginBottom: '1.5rem'
            }}>
              <div style={{
                background: 'white',
                borderRadius: '12px',
                padding: '1rem',
                border: '1px solid #e2e8f0'
              }}>
                <div style={{
                  fontSize: '1.3rem',
                  fontWeight: 'bold',
                  color: '#48bb78',
                  marginBottom: '0.25rem'
                }}>
                  ₹1400
                </div>
                <div style={{
                  fontSize: '0.85rem',
                  color: '#718096'
                }}>
                  Weekly Protected
                </div>
              </div>

              <div style={{
                background: 'white',
                borderRadius: '12px',
                padding: '1rem',
                border: '1px solid #e2e8f0'
              }}>
                <div style={{
                  fontSize: '1.3rem',
                  fontWeight: 'bold',
                  color: '#4a5568',
                  marginBottom: '0.25rem'
                }}>
                  ₹2000
                </div>
                <div style={{
                  fontSize: '0.85rem',
                  color: '#718096'
                }}>
                  Total Potential
                </div>
              </div>

              <div style={{
                background: 'white',
                borderRadius: '12px',
                padding: '1rem',
                border: '1px solid #e2e8f0'
              }}>
                <div style={{
                  fontSize: '1.3rem',
                  fontWeight: 'bold',
                  color: '#ed8936',
                  marginBottom: '0.25rem'
                }}>
                  ₹600
                </div>
                <div style={{
                  fontSize: '0.85rem',
                  color: '#718096'
                }}>
                  At Risk
                </div>
              </div>
            </div>

            {/* Impact Message */}
            <div style={{
              background: 'linear-gradient(135deg, #667eea, #764ba2)',
              color: 'white',
              borderRadius: '12px',
              padding: '1rem 1.5rem',
              display: 'inline-block',
              fontSize: '0.95rem',
              fontWeight: '500',
              boxShadow: '0 4px 15px rgba(102, 126, 234, 0.3)'
            }}>
              🛡️ <strong>70% of weekly earnings</strong> protected by parametric insurance
            </div>
          </div>
        </div>

        <style jsx>{`
          @keyframes pulse {
            0%, 100% { opacity: 0.05; }
            50% { opacity: 0.1; }
          }
        `}</style>
      </div>

      {/* Enhanced Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card" style={{
          background: 'linear-gradient(135deg, #ebf8ff, #bee3f8)',
          borderLeft: '4px solid #3182ce',
          boxShadow: '0 4px 20px rgba(49, 130, 206, 0.15)'
        }}>
          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            marginBottom: '0.5rem',
            gap: '0.5rem'
          }}>
            <div style={{ 
              fontSize: '1.5rem', 
              color: '#3182ce' 
            }}>🛡️</div>
            <div className="stat-value" style={{ color: '#2c5282' }}>{stats.activePolicies}</div>
          </div>
          <div className="stat-label" style={{ color: '#2c5282', fontWeight: '600' }}>Active Weekly Policies</div>
          <div className="stat-change positive" style={{ 
            background: 'rgba(72, 187, 120, 0.1)', 
            color: '#22543d',
            borderRadius: '20px',
            padding: '0.25rem 0.5rem',
            fontSize: '0.8rem'
          }}>
            ↑ 12% from last week
          </div>
        </div>

        <div className="stat-card" style={{
          background: 'linear-gradient(135deg, #f0fdf4, #dcfce7)',
          borderLeft: '4px solid #48bb78',
          boxShadow: '0 4px 20px rgba(72, 187, 120, 0.15)'
        }}>
          <div style={{ 
            display: 'flex', 
            alignItems: 'center', 
            marginBottom: '0.5rem',
            gap: '0.5rem'
          }}>
            <div style={{ 
              fontSize: '1.5rem', 
              color: '#48bb78' 
            }}>📈</div>
