                <th>Risk Level</th>
              </tr>
            </thead>
            <tbody>
              {workers.map((worker) => (
                <tr key={worker.id}>
                  <td>{worker.name}</td>
                  <td>{worker.city}</td>
                  <td>₹{worker.premium}</td>
